insert into public.vehicles (slug, make, model, year, category, daily_rate, description, location, featured, available) values
  ('2019-mclaren-570s-orange', 'McLaren', '570S (Orange)', 2019, 'supercar', 1200, 'A 2019 McLaren 570S in McLaren Volcano Orange — the entry-level pure-supercar from Woking, England. Mid-mounted twin-turbo 3.8L V8 producing 562 hp, dual-clutch 7-speed, RWD, 0–60 in 3.1 seconds, top speed 204 mph. Carbon-fiber MonoCell II chassis, dihedral doors, and McLaren''s hallmark visible engine bay. Lightweight, surgical handling, and the kind of supercar that delivers a track-grade driving experience without the temperament of a Ferrari.', 'Miami, FL', false, true),
  ('2022-lamborghini-hurracan-evo-sp', 'Lamborghini', 'Huracán EVO Spyder', 2022, 'convertible', 1800, 'A 2022 Lamborghini Huracán EVO Spyder — the convertible variant of the Huracán EVO. Naturally aspirated 5.2L V10 producing 631 hp, AWD, 7-speed dual-clutch, 0–60 in 3.1 seconds, top speed 202 mph. Soft top retracts in 17 seconds at speeds up to 31 mph, dynamic rear-wheel steering, magnetorheological dampers, and Lamborghini Dynamica Vehicle Integrata (LDVI) AI. The naturally-aspirated V10 howl is the soundtrack of South Beach.', 'Miami, FL', false, true),
  ('2022-mercedes-party-van-13ppl-ma', 'Mercedes-Benz', 'Sprinter Party Van (13-passenger)', 2022, 'suv', 900, 'A 2022 Mercedes-Benz Sprinter party van seating 13 passengers — luxury group transport with a custom-built party-bus interior including LED ambient lighting, leather wraparound bench seating, full sound system, refreshment area, premium audio, and tinted privacy windows. 3.0L V6 turbo diesel, the standard for executive shuttling, bachelor/bachelorette runs, and party transit between marinas, restaurants, and clubs.', 'Miami, FL', false, true),
  ('2023-mercedes-g63-amg-gwagon', 'Mercedes-AMG', 'G63 (G-Wagon)', 2023, 'suv', 1200, 'A 2023 Mercedes-AMG G63 — the iconic boxy SUV reborn with AMG performance. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking diferentials, 0–60 in 4.4 seconds, and the unmistakable upright G-Class silhouette refined for the modern era. Big AMG Panamericana grille, side-exit AMG quad exhaust, and 22-inch AMG wheels. The G63 is the benchmark luxury off-roader and the ultimate Miami status SUV.', 'Miami, FL', false, true),
  ('2024-lamborghini-urus-s', 'Lamborghini', 'Urus S', 2024, 'suv', 1500, 'A 2024 Lamborghini Urus S — the super-SUV that redefined the segment. Twin-turbo 4.0L V8 producing 657 hp, AWD with active rear-wheel steering, 0–60 in 3.4 seconds, top speed 190 mph. Aggressive Lamborghini-pentagon styling with hexagonal exhaust tips, scissor-style doors not included but plenty of ground presence. The Urus S replaces the original Urus with sharper styling, more power, and a meaner exhaust note.', 'Miami, FL', false, true),
  ('2024-mclaren-artura-red-blk', 'McLaren', 'Artura (Red/Black)', 2024, 'supercar', 2000, 'A 2024 McLaren Artura in red over black — McLaren''s first hybrid supercar. Twin-turbo 3.0L V6 paired with a 94 hp electric motor producing 671 hp combined, 8-speed dual-clutch, RWD, 0–60 in 2.6 seconds, top speed 205 mph. Carbon-fiber McLaren Carbon Lightweight Architecture (MCLA), dihedral doors, ~21 miles of all-electric range. The future of the supercar from McLaren.', 'Miami, FL', false, true),
  ('2025-china-blue-g-wagon', 'Mercedes-AMG', 'G 63 (China Blue)', 2025, 'suv', 1300, 'A 2025 Mercedes-AMG G 63 in China Blue exterior — the rare Manufaktur paint code that is impossible to miss in any Miami valet line. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking differentials, 0–60 in 4.4 seconds. AMG Panamericana grille, AMG side-exit quad exhaust, and the unmistakable boxy G-Wagon silhouette in showstopping blue.', 'Miami, FL', false, true),
  ('2025-corvette-stingray-white-interior', 'Chevrolet', 'Corvette C8 Stingray (White Interior)', 2025, 'supercar', 450, 'A 2025 Chevrolet Corvette C8 Stingray with the rare white leather interior package. Mid-engine 6.2L LT2 V8 producing 495 hp with Z51 Performance Package, 8-speed dual-clutch, RWD, 0–60 in 2.9 seconds. Removable carbon-fiber roof panel, 5-spoke wheels, and the divisive square-pattern white interior that splits supercar opinion. American mid-engine supercar.', 'Miami, FL', false, true),
  ('2025-escalade-platinum', 'Cadillac', 'Escalade Platinum', 2025, 'suv', 700, 'A 2025 Cadillac Escalade Platinum — the flagship trim of the full-size Cadillac SUV. 6.2L V8 producing 420 hp or available 3.0L Duramax inline-six diesel, RWD or 4WD, magnetic ride control, full air suspension, and the brand-new 55-inch curved OLED dashboard display spanning the full width of the cabin. Three rows, executive captain seats, AKG 36-speaker audio, and the Super Cruise hands-free highway driving system. The American luxury SUV benchmark. (Note: gallery images were not retrievable from the source listing.)', 'Miami, FL', false, true),
  ('2025-mclaren-artura-spider', 'McLaren', 'Artura Spider', 2025, 'convertible', 2200, 'A 2025 McLaren Artura Spider — the convertible variant of McLaren''s hybrid supercar. Twin-turbo 3.0L V6 paired with a 94 hp electric motor producing 690 hp combined, 8-speed dual-clutch, RWD, 0–60 in 3.0 seconds, top speed 205 mph. Retractable hardtop, carbon-fiber McLaren Carbon Lightweight Architecture (MCLA), dihedral doors, and ~21 miles of all-electric range. (Note: gallery images were not retrievable from the source listing.)', 'Miami, FL', false, true),
  ('2025-porsche-911-targa-4s-1-4-cu', 'Porsche', '911 Targa 4S', 2025, 'convertible', 1000, 'A 2025 Porsche 911 Targa 4S — the targa-top variant of the iconic 911. Twin-turbo 3.0L flat-six producing 443 hp, 8-speed PDK, AWD via 4S, 0–60 in 3.4 seconds. The Targa''s signature retractable hardtop opens automatically with a theatrical mechanical ballet. 992-generation styling with full-width LED light bar, Targa silver roll bar, and the timeless 911 silhouette. The connoisseur''s 911.', 'Miami, FL', false, true),
  ('2026-range-rover-sport', 'Range Rover', 'Sport', 2026, 'suv', 700, 'A 2026 Range Rover Sport — the sportier sibling to the flagship Range Rover, refreshed for 2026. Available in supercharged P440e PHEV (434 hp), P530 V8 (523 hp), or SV trim. Air suspension, terrain response 2, electronic active differential, and the latest Pivi Pro infotainment. Off-road capable while delivering on-road sportiness — the British SUV gold standard for daily luxury.', 'Miami, FL', false, true),
  ('aventador-s', 'Lamborghini', 'Aventador S', 2024, 'hypercar', 2500, 'A Lamborghini Aventador S — the mid-cycle refresh of the Aventador. Naturally aspirated 6.5L V12 producing 730 hp, AWD with Lamborghini Dynamic Steering and rear-wheel steering, 7-speed single-clutch automated manual, 0–60 in 2.9 seconds, top speed 217 mph. Scissor doors, ferocious aero, Lamborghini-pentagonal bodywork. The V12 Lamborghini soundtrack is unmatched in production.', 'Miami, FL', false, true),
  ('aventador-svj-gintani', 'Lamborghini', 'Aventador SVJ (Gintani Exhaust)', 2024, 'hypercar', 3500, 'A Lamborghini Aventador SVJ with a Gintani aftermarket exhaust — already the most extreme V12 Aventador, now with a sound that registers on seismic sensors. Naturally aspirated 6.5L V12 producing 759 hp (760 PS), AWD with rear-wheel steering, 7-speed single-clutch, 0–60 in 2.8 seconds, top speed 217 mph. Active aero (ALA 2.0), aggressive scissor doors. Held the Nürburgring production-car lap record at debut.', 'Miami, FL', false, true),
  ('bmw-m340i-blue', 'BMW', 'M340i (G20)', 2024, 'supercar', 275, 'A Portimao Blue BMW M340i, the M Performance variant of the 3 Series. Twin-turbo 3.0L inline-six producing 382 hp paired with xDrive AWD, 0–60 in 4.1 seconds. M Sport bodywork, gloss black kidney grille, and aggressive side skirts. Interior shows BMW''s curved widescreen iDrive display and the M Sport flat-bottom steering wheel paired with cognac leather seats — an executive sports sedan that splits the difference between a 330i and a full M3.', 'Miami, FL', false, true),
  ('bmw-m4-competition-convertible-whiteorange', 'BMW', 'M4 Competition Convertible (White/Orange)', 2024, 'convertible', 650, 'A BMW M4 Competition Convertible in Alpine White over Sakhir Orange interior. Twin-turbo S58 3.0L inline-six producing 503 hp, M xDrive AWD, 8-speed M Steptronic, 0–60 in 3.6 seconds. Soft-top retracts in 18 seconds at speeds up to 31 mph. Massive BMW kidney grille (love-it-or-hate-it), carbon fiber accents, and orange-stitched leather Merino sport seats. M Performance with full open-air freedom.', 'Miami, FL', false, true),
  ('bentley-bentayga', 'Bentley', 'Bentayga', 2024, 'suv', 1400, 'A Bentley Bentayga — the British luxury SUV from Bentley. Twin-turbo 4.0L V8 producing 542 hp, AWD, 0–60 in 4.4 seconds, top speed 180 mph. Hand-stitched Bentley leather throughout, four-zone climate, optional rear executive seats, Bentley Naim audio, and the unmistakable matrix grille and round Bentley headlights. The Bentayga is for owners who want the SUV practicality with Crewe-built Bentley craftsmanship. (Note: gallery images were not retrievable from the source listing.)', 'Miami, FL', false, true),
  ('bugatti-chiron', 'Bugatti', 'Chiron', 2024, 'hypercar', 30000, 'A Bugatti Chiron — the apex hypercar from Molsheim, France. Quad-turbocharged 8.0L W16 producing 1,479 hp / 1,180 lb-ft, AWD, 7-speed dual-clutch, 0–60 in 2.4 seconds, electronically limited top speed 261 mph (unrestricted Super Sport variant has hit 304 mph). Carbon-fiber monocoque, dihedral doors, and the iconic Bugatti horseshoe grille. One of approximately 500 ever built. Renting a Chiron is a flex few can match.', 'Miami, FL', false, true),
  ('c8-z06', 'Chevrolet', 'Corvette C8 Z06', 2024, 'supercar', 700, 'A Chevrolet Corvette C8 Z06 — the track-focused, naturally-aspirated, flat-plane V8 Corvette. 5.5L LT6 V8 producing 670 hp at 8,400 rpm — the most powerful naturally aspirated V8 in any production car. RWD, 8-speed dual-clutch, 0–60 in 2.6 seconds, top speed 195 mph. Magnetic Ride Control, carbon ceramic brake option, and Z07 track package available. American mid-engine track weapon.', 'Miami, FL', false, true),
  ('chevrolet-corvette-coupe-yellowblack', 'Chevrolet', 'Corvette C8 Stingray Coupe (Yellow/Black)', 2024, 'supercar', 450, 'A Chevrolet Corvette C8 Stingray Coupe in Accelerate Yellow over black interior. Mid-engine 6.2L LT2 V8 producing 495 hp with the Z51 Performance Package, 8-speed dual-clutch, RWD, 0–60 in 2.9 seconds. Removable carbon-fiber roof panel, 5-spoke wheels, and the bright-yellow paint that turns every supermarket trip into a parade. American mid-engine supercar at a quarter of European competitor pricing.', 'Miami, FL', false, true),
  ('chevrolet-corvette-z06-convertible-redblack', 'Chevrolet', 'Corvette C8 Z06 Convertible (Red/Black)', 2024, 'convertible', 900, 'A Chevrolet Corvette C8 Z06 Convertible in Torch Red over black interior. Naturally aspirated flat-plane 5.5L LT6 V8 producing 670 hp at 8,400 rpm — the most powerful naturally aspirated V8 in any production car. Hardtop convertible, 0–60 in 2.6 seconds, top speed 195 mph. Magnetic Ride Control, carbon ceramic brake option, and the Z07 track package available. Mid-engine American supercar at a fraction of the European competition.', 'Miami, FL', false, true),
  ('corvette-c8-convertible', 'Chevrolet', 'Corvette C8 Stingray Convertible', 2024, 'convertible', 500, 'A Chevrolet Corvette C8 Stingray Convertible — the open-top mid-engine Corvette. 6.2L LT2 V8 producing 495 hp with the Z51 Performance Package, 8-speed dual-clutch, RWD, 0–60 in 2.9 seconds. Hardtop convertible folds in 16 seconds at speeds up to 30 mph. American mid-engine supercar at a quarter of European competitor pricing.', 'Miami, FL', false, true),
  ('corvette-c8-z51-blue', 'Chevrolet', 'Corvette C8 Z51', 2024, 'supercar', 395, 'A Rapid Blue Corvette C8 Z51 parked at a gated estate, mid-engine supercar profile in full view. The Z51 Performance Package adds upgraded brakes (red painted calipers visible), performance suspension, electronic limited-slip differential, performance exhaust, and a higher-output 6.2L V8 making 495 hp. 0–60 in roughly 2.9 seconds. Interior shot shows the squared-off racing-style steering wheel and Corvette''s signature wraparound cockpit with red accents. American supercar territory at half the price of the European competition.', 'Miami, FL', false, true),
  ('corvette-c8-z51-orange', 'Chevrolet', 'Corvette C8 Z51', 2024, 'supercar', 375, 'An Amplify Orange Corvette C8 Z51 indoors in a parking garage — the loudest factory color GM offers on the C8. The Z51 Performance Package adds upgraded brakes, performance suspension, electronic limited-slip differential, performance exhaust, and the higher-output 6.2L V8 making 495 hp. 0–60 in roughly 2.9 seconds. Black 5-spoke wheels and gloss black side intakes contrast against the bright orange paint. Interior shows the squared-off racing-style steering wheel and Natural Tan leather GT2 seats — a mid-engine American supercar that punches well above its sticker price.', 'Miami, FL', false, true),
  ('corvette-c8-z51-white', 'Chevrolet', 'Corvette C8 Z51', 2024, 'supercar', 375, 'An Arctic White Corvette C8 Z51 in a covered parking deck, the mid-engine American supercar in its purest form. The Z51 Performance Package brings upgraded brakes with bright yellow-painted calipers (visible behind the black 5-spoke wheels), performance suspension, electronic limited-slip differential, performance exhaust, and the higher-output 6.2L V8 making 495 hp. 0–60 in roughly 2.9 seconds. Clean factory-spec example with a low, wide stance.', 'Miami, FL', false, true),
  ('cullinan', 'Rolls-Royce', 'Cullinan', 2024, 'suv', 2500, 'A Rolls-Royce Cullinan — the only SUV from Rolls-Royce. Twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.8 seconds, top speed 155 mph. Air suspension, rear-wheel steering, magic carpet ride quality, and a stand-up tailgate "Recreation Module" with cocktail or viewing platform. The Cullinan is the ultimate luxury SUV — Rolls-Royce gravitas in a daily-driver chassis.', 'Miami, FL', false, true),
  ('custom-rr-cullinan-tiffany-blue', 'Rolls-Royce', 'Cullinan (Custom Tiffany Blue)', 2024, 'suv', 3000, 'A Rolls-Royce Cullinan in custom Tiffany Blue — the unmistakable Tiffany & Co. signature shade applied to a Rolls-Royce SUV. Twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.8 seconds. Air suspension, rear-wheel steering, and the magic-carpet Rolls-Royce ride quality. The Tiffany Blue spec is one of the most photographed Cullinans in Miami.', 'Miami, FL', false, true),
  ('dodge-durango-srt-hellcat', 'Dodge', 'Durango SRT Hellcat', 2024, 'suv', 350, 'A Destroyer Gray Dodge Durango SRT Hellcat with twin yellow racing stripes running the full length of the body. The fastest, most powerful 3-row SUV ever built — supercharged 6.2L Hemi V8 making 710 hp and 645 lb-ft of torque, 0–60 in 3.5 seconds, top speed of 180 mph. Yellow Brembo six-piston front calipers visible behind the satin black wheels. Interior shows the SRT-branded steering wheel and full performance gauge cluster. A family hauler that out-runs most supercars.', 'Miami, FL', false, true),
  ('escalade-esv-sport', 'Cadillac', 'Escalade ESV Sport', 2024, 'suv', 700, 'A Cadillac Escalade ESV Sport — extended wheelbase, blacked-out Sport trim. 6.2L V8 producing 420 hp, 4WD, magnetic ride control, full air suspension, 38-inch curved OLED display dashboard. Three rows of seating, executive second-row captain seats, AKG 36-speaker audio, and the imposing American luxury SUV silhouette.', 'Miami, FL', false, true),
  ('escalade-esv-sport-2025', 'Cadillac', 'Escalade ESV Sport', 2025, 'suv', 750, 'A 2025 Cadillac Escalade ESV Sport — extended wheelbase, blacked-out Sport trim. 6.2L V8 producing 420 hp or available 3.0L Duramax diesel, magnetic ride control, full air suspension, and the new 55-inch curved OLED dashboard display. Three rows of seating, AKG 36-speaker audio, Super Cruise hands-free highway driving. The Escalade benchmark for executive group transport.', 'Miami, FL', false, true),
  ('escalade-esv-sport-platinum-2025', 'Cadillac', 'Escalade ESV Sport Platinum', 2025, 'suv', 800, 'A 2025 Cadillac Escalade ESV Sport Platinum — the extended wheelbase, top-trim flagship with the Sport package. ESV adds 14.3 inches of length and 26.5 cubic feet of cargo. 6.2L V8 producing 420 hp or available 3.0L Duramax inline-six diesel, magnetic ride control, full air suspension, and the brand-new 55-inch curved OLED dashboard display. Three rows, executive captain seats, AKG 36-speaker audio, Super Cruise hands-free highway driving, and the blacked-out Sport trim styling.', 'Miami, FL', false, true),
  ('escalade-esv-sport-2', 'Cadillac', 'Escalade ESV Sport', 2024, 'suv', 700, 'A Cadillac Escalade ESV Sport — extended wheelbase configuration with the blacked-out Sport trim package. 6.2L V8 producing 420 hp, magnetic ride control, full air suspension, three-row seating with executive captain second-row seats, AKG 36-speaker audio. The benchmark for American luxury group transport.', 'Miami, FL', false, true),
  ('ferrari-488-spider', 'Ferrari', '488 Spider', 2024, 'convertible', 2200, 'A Ferrari 488 Spider — the convertible variant of the 488 GTB. Mid-mounted twin-turbo 3.9L V8 producing 661 hp, 7-speed dual-clutch, RWD, 0–60 in 3.0 seconds, top speed 203 mph. Retractable hardtop folds in 14 seconds at speeds up to 25 mph. The 488 was Ferrari''s last small-V8 supercar before the F8 Tributo replaced it — a classic-feel mid-engine Ferrari with all the cachet that brings.', 'Miami, FL', false, true),
  ('ferrari-f8-tributo-berlinetta-whitered', 'Ferrari', 'F8 Tributo (White/Red)', 2024, 'supercar', 2500, 'A Ferrari F8 Tributo in Bianco Avus over Rosso Ferrari interior. Mid-mounted twin-turbo 3.9L V8 producing 710 hp, 7-speed dual-clutch, RWD, 0–60 in 2.9 seconds, top speed 211 mph. The F8 is the final Ferrari V8 berlinetta before electrification, named in tribute to the most awarded engine in Ferrari history. Active aero with S-duct, carbon-fiber components, and a soundtrack that justifies the price tag.', 'Miami, FL', false, true),
  ('ferrari-purosangue', 'Ferrari', 'Purosangue', 2024, 'suv', 3500, 'A Ferrari Purosangue — Ferrari''s first SUV/four-door, named "Pure Blood" in Italian. Naturally aspirated 6.5L V12 producing 715 hp — one of the only naturally aspirated V12s in any new SUV — AWD, 0–60 in 3.2 seconds, top speed 193 mph. Suicide-hinged rear doors, four individual seats (no middle seat), and a price tag and waitlist that mark it as Ferrari''s most exclusive model since the LaFerrari.', 'Miami, FL', false, true),
  ('g63-amg-whiteout', 'Mercedes-AMG', 'G 63 (Whiteout)', 2024, 'suv', 1200, 'A Mercedes-AMG G 63 in full whiteout spec — Polar White exterior with white wheels, white interior, and color-matched body trim. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking differentials, 0–60 in 4.4 seconds. AMG Panamericana grille, AMG side-exit quad exhaust, and the unmistakable boxy G-Wagon silhouette in monochrome white.', 'Miami, FL', false, true),
  ('g63-amg', 'Mercedes-AMG', 'G 63', 2024, 'suv', 1200, 'A Mercedes-AMG G 63 — the iconic boxy SUV with AMG performance. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking differentials, 0–60 in 4.4 seconds. AMG Panamericana grille, AMG side-exit quad exhaust, 22-inch AMG wheels, and the unmistakable G-Wagon silhouette refined for the modern era. The benchmark luxury off-roader and the ultimate Miami status SUV.', 'Miami, FL', false, true),
  ('gls-600-maybach', 'Mercedes-Maybach', 'GLS 600', 2024, 'suv', 1800, 'A Mercedes-Maybach GLS 600 — the flagship Maybach SUV. Twin-turbo 4.0L V8 with EQ Boost producing 550 hp, 4MATIC AWD, 0–60 in 4.8 seconds. Maybach-exclusive double-louvre grille, Executive Rear Seat Package with reclining captain chairs, refrigerator, and rear entertainment. The ultimate chauffeured luxury SUV.', 'Miami, FL', false, true),
  ('huracan-sto', 'Lamborghini', 'Huracán STO', 2024, 'hypercar', 3000, 'A Lamborghini Huracán STO ("Super Trofeo Omologata") — the most extreme road-legal Huracán, derived directly from the Huracán Super Trofeo and GT3 race cars. Naturally aspirated 5.2L V10 producing 631 hp, RWD, 0–60 in 3.0 seconds, top speed 193 mph. 75% of the body panels are carbon fiber, single-piece "cofango" front clamshell, massive fixed rear wing, magnesium wheels, and a track-focused interior. The track-day Huracán.', 'Miami, FL', false, true),
  ('immersive-cullinan', 'Rolls-Royce', 'Cullinan (Immersive Spec)', 2024, 'suv', 2800, 'A Rolls-Royce Cullinan in an "Immersive" custom specification — full bespoke commission via Rolls-Royce Provenance program with rare Mansory or Spofec aero kit, custom paint, forged wheels, and bespoke leather. Underneath: twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.8 seconds. Air suspension, rear-wheel steering, and the magic-carpet Rolls-Royce ride quality.', 'Miami, FL', false, true),
  ('keyvany-keyrus-urus', 'Keyvany', 'Keyrus (Urus widebody)', 2024, 'suv', 2500, 'A Keyvany Keyrus — the Stuttgart-based Keyvany tuning house''s carbon-fiber widebody Lamborghini Urus conversion. Adds 100mm of width front and rear via fully forged carbon fiber components, custom front bumper, splitter, side skirts, fender vents, hood, and rear diffuser. Tuned to ~782 hp on the standard 4.0L V8 program. One of the wildest carbon-fiber widebody Urus builds ever made.', 'Miami, FL', false, true),
  ('lamborghini-huracan', 'Lamborghini', 'Huracán', 2024, 'supercar', 1800, 'A Lamborghini Huracán — the V10-powered "baby Lambo" that has become the defining modern supercar. Naturally aspirated 5.2L V10 producing 631 hp (in EVO trim), AWD, 7-speed dual-clutch, 0–60 in 2.9 seconds, top speed 202 mph. Carbon-fiber and aluminum hybrid chassis, magnetorheological dampers, and the Lamborghini-pentagonal bodywork. The naturally-aspirated V10 howl is one of the great supercar soundtracks.', 'Miami, FL', false, true),
  ('lamborghini-urus', 'Lamborghini', 'Urus', 2024, 'suv', 1500, 'A Lamborghini Urus — the super-SUV that redefined the segment. Twin-turbo 4.0L V8 producing 641 hp, AWD with active rear-wheel steering and torque vectoring, 0–60 in 3.4 seconds, top speed 190 mph. Aggressive Lamborghini-pentagon styling with hexagonal exhaust tips. The most usable Lamborghini ever made.', 'Miami, FL', false, true),
  ('lamborghini-huracan-evo2', 'Lamborghini', 'Huracán EVO', 2024, 'supercar', 1800, 'A Lamborghini Huracán EVO — the mid-cycle refresh of the Huracán. Naturally aspirated 5.2L V10 producing 631 hp, AWD, 7-speed dual-clutch, 0–60 in 2.9 seconds, top speed 202 mph. Lamborghini Dynamica Vehicle Integrata (LDVI) AI-driven AWD, dynamic rear-wheel steering, magnetorheological dampers, and enhanced aero. The naturally-aspirated V10 howl is one of the great supercar soundtracks.', 'Miami, FL', false, true),
  ('lamborghini-huracan-evo-green', 'Lamborghini', 'Huracán EVO (Verde Selvans Green)', 2024, 'supercar', 1800, 'A Lamborghini Huracán EVO in Verde Selvans (or similar Lamborghini matte-green). Naturally aspirated 5.2L V10 producing 631 hp, AWD, 7-speed dual-clutch, 0–60 in 2.9 seconds, top speed 202 mph. Lamborghini Dynamica Vehicle Integrata (LDVI) AI-driven AWD, dynamic rear-wheel steering, magnetorheological dampers, and the bright matte green that owns every Miami valet line.', 'Miami, FL', false, true),
  ('lamborghini-huracan-evo-spyder', 'Lamborghini', 'Huracán EVO Spyder', 2024, 'convertible', 1900, 'A Lamborghini Huracán EVO Spyder — the convertible variant of the Huracán EVO. Naturally aspirated 5.2L V10 producing 631 hp, AWD, 7-speed dual-clutch, 0–60 in 3.1 seconds, top speed 202 mph. Soft top retracts in 17 seconds at speeds up to 31 mph, dynamic rear-wheel steering, magnetorheological dampers, and the LDVI AI-driven AWD system. The naturally-aspirated V10 howl is the soundtrack of South Beach.', 'Miami, FL', false, true),
  ('lamborghini-huracan-tecnica', 'Lamborghini', 'Huracán Tecnica', 2024, 'supercar', 2500, 'A Lamborghini Huracán Tecnica — the rear-wheel-drive sharpened-Huracán positioned between the EVO RWD and the track-focused STO. Naturally aspirated 5.2L V10 producing 631 hp, RWD, 7-speed dual-clutch, 0–60 in 3.2 seconds, top speed 202 mph. STO-derived aero, lightweight forged wheels, and a redesigned front bumper with vertical "Y" daytime lights. The driver''s Huracán.', 'Miami, FL', false, true),
  ('lamborghini-urus-blackblack', 'Lamborghini', 'Urus (Black/Black)', 2024, 'suv', 1500, 'A Lamborghini Urus in Nero Noctis over black interior — the murdered-out spec. Twin-turbo 4.0L V8 producing 641 hp, AWD with active rear-wheel steering, 0–60 in 3.4 seconds, top speed 190 mph. Black 23-inch wheels, blacked-out exhaust tips, and full carbon-fiber accents. Stealth Lamborghini ground presence — sinister, fast, and unmistakable.', 'Miami, FL', false, true),
  ('lamborghini-urus-blueblack', 'Lamborghini', 'Urus (Blue/Black)', 2024, 'suv', 1500, 'A Lamborghini Urus in Blu Astraeus over black interior. Twin-turbo 4.0L V8 producing 641 hp, AWD with active rear-wheel steering and torque vectoring, 0–60 in 3.4 seconds, top speed 190 mph. Aggressive Lamborghini-pentagon styling with hexagonal exhaust tips, full carbon-fiber accent package, and 23-inch Y-spoke wheels. The most usable Lamborghini ever made.', 'Miami, FL', false, true),
  ('lamborghini-urus-performante-2024', 'Lamborghini', 'Urus Performante', 2024, 'suv', 2000, 'A 2024 Lamborghini Urus Performante — the track-focused, lightened, more powerful Urus. Twin-turbo 4.0L V8 producing 657 hp, AWD with center diff biased rearward, 0–60 in 3.3 seconds, top speed 190 mph. 47mm wider track, 20mm lowered ride height, carbon-fiber hood with NACA ducts, fixed roof spoiler, and titanium Akrapovič exhaust. The fastest production SUV around the Nürburgring at its 2022 launch.', 'Miami, FL', false, true),
  ('lamborghini-urus-redblack-white', 'Lamborghini', 'Urus (Red/Black-White)', 2024, 'suv', 1500, 'A Lamborghini Urus in Rosso Mars red exterior with black/white interior. Twin-turbo 4.0L V8 producing 641 hp, AWD with active rear-wheel steering and torque vectoring, 0–60 in 3.4 seconds, top speed 190 mph. Aggressive Lamborghini-pentagon styling with hexagonal exhaust tips, carbon accents, and the bright red factory paint that owns any Miami marina valet stand.', 'Miami, FL', false, true),
  ('lamborghini-urus-s', 'Lamborghini', 'Urus S', 2024, 'suv', 1500, 'A Lamborghini Urus S — the refreshed Urus replacing the original. Twin-turbo 4.0L V8 producing 657 hp, AWD with active rear-wheel steering, 0–60 in 3.4 seconds, top speed 190 mph. Aggressive Lamborghini-pentagon styling with hexagonal exhaust tips. The Urus S brings sharper styling and more power to the standard Urus formula.', 'Miami, FL', false, true),
  ('lamborghini-urus-se-2026', 'Lamborghini', 'Urus SE', 2026, 'suv', 2200, 'A 2026 Lamborghini Urus SE — the plug-in hybrid evolution of the Urus, replacing the original Urus and Urus S. Twin-turbo 4.0L V8 paired with an electric motor producing 789 hp combined / 701 lb-ft, AWD with rear-axle e-motor, 0–60 in 3.1 seconds, top speed 194 mph, ~37 miles of EV range. Refreshed Lamborghini-pentagon styling, larger displays, and the most powerful Urus yet.', 'Miami, FL', false, true),
  ('lamborghini-urus-wide-body', 'Lamborghini', 'Urus Widebody (Custom)', 2024, 'suv', 2000, 'A widebody-converted Lamborghini Urus — the factory super-SUV taken further with aftermarket widebody fenders, custom forged wheels, lowered suspension, and aggressive aero. Underneath the bodywork remains the twin-turbo 4.0L V8 producing 641+ hp depending on tune, AWD, 0–60 in 3.4 seconds. Ground-presence dialed past stock levels, the kind of car that stops conversation on Ocean Drive.', 'Miami, FL', false, true),
  ('mercedes-s580', 'Mercedes-Benz', 'S 580', 2024, 'sedan', 650, 'A Mercedes-Benz S 580 — the flagship S-Class luxury sedan. Twin-turbo 4.0L V8 with EQ Boost producing 496 hp, 4MATIC AWD, 0–60 in 4.4 seconds. AMG-styling Line bodywork available, multi-spoke 21-inch wheels, and the iconic Mercedes grille with three-pointed star hood ornament. Interior features the massive portrait MBUX Hyperscreen, executive rear seats option, and the new-generation steering wheel with capacitive controls.', 'Miami, FL', false, true),
  ('maybach-gls600-with-stars-white', 'Mercedes-Maybach', 'GLS 600 with Starlight Headliner (White)', 2024, 'suv', 1800, 'A Mercedes-Maybach GLS 600 in Diamond White with the Maybach Starlight headliner — the flagship Maybach SUV. Twin-turbo 4.0L V8 with EQ Boost producing 550 hp, 4MATIC AWD, 0–60 in 4.8 seconds. Maybach-exclusive double-louvre grille, Executive Rear Seat Package with reclining captain chairs, refrigerator, champagne flutes, two screens, and the fiber-optic starlight headliner. The ultimate chauffeured experience.', 'Miami, FL', false, true),
  ('maybach-gls600', 'Mercedes-Maybach', 'GLS 600', 2024, 'suv', 1800, 'A Mercedes-Maybach GLS 600 — the flagship Maybach SUV. Twin-turbo 4.0L V8 with EQ Boost producing 550 hp, 4MATIC AWD, 0–60 in 4.8 seconds. Maybach-exclusive double-louvre grille, Executive Rear Seat Package with reclining captain chairs, refrigerator, and rear entertainment. The ultimate chauffeured luxury SUV.', 'Miami, FL', false, true),
  ('maybach-s580', 'Mercedes-Maybach', 'S 580', 2024, 'sedan', 1400, 'A Mercedes-Maybach S 580 — the Maybach version of the flagship S-Class. Twin-turbo 4.0L V8 with EQ Boost producing 496 hp, 4MATIC AWD, 0–60 in 4.4 seconds. Maybach-specific two-tone paintwork available, extended wheelbase, executive rear seats with massage and recline, dual rear-screen entertainment system, and a refrigerator with champagne flutes. The standard for chauffeured Miami transport.', 'Miami, FL', false, true),
  ('maybach-s680-v12', 'Mercedes-Maybach', 'S 680 V12', 2024, 'sedan', 2000, 'A Mercedes-Maybach S 680 — the V12-powered flagship of the Maybach S-Class. Twin-turbo 6.0L V12 producing 621 hp / 664 lb-ft, RWD, 0–60 in 4.4 seconds. The V12 is one of the few remaining in any production sedan and is the headline feature: silent torque delivery, exclusive Maybach styling cues, executive rear seats with Mercedes-Benz Magic Body Control, and the fiber-optic starlight headliner option. Heads-of-state-grade luxury.', 'Miami, FL', false, true),
  ('mclaren-570gt', 'McLaren', '570GT', 2024, 'supercar', 1100, 'A McLaren 570GT — the grand-tourer variant of the 570S with added practicality. Mid-mounted twin-turbo 3.8L V8 producing 562 hp, dual-clutch 7-speed, RWD, 0–60 in 3.1 seconds, top speed 204 mph. The GT adds a side-opening glass touring deck for luggage, a softer chassis tune, and added sound deadening for long-distance comfort while keeping the McLaren MonoCell II carbon chassis. Practical supercar.', 'Miami, FL', false, true),
  ('mclaren-720s-custom', 'McLaren', '720S (Custom)', 2024, 'supercar', 2500, 'A custom-spec McLaren 720S — likely with aftermarket aero, custom forged wheels, and a bespoke paint or vinyl wrap. Mid-mounted twin-turbo 4.0L V8 producing 710 hp, 7-speed dual-clutch, RWD, 0–60 in 2.7 seconds, top speed 212 mph. McLaren Carbon Fiber MonoCage II monocoque, dihedral doors, and the iconic floating side-intakes. The 720S is widely regarded as one of the best supercars of the modern era.', 'Miami, FL', false, true),
  ('mclaren-artura-spider-silverred', 'McLaren', 'Artura Spider (Silver/Red)', 2024, 'convertible', 2200, 'A McLaren Artura Spider in silver over red interior — the convertible variant of the Artura hybrid supercar. Twin-turbo 3.0L V6 paired with a 94 hp electric motor producing 690 hp combined, 8-speed dual-clutch, RWD, 0–60 in 3.0 seconds, top speed 205 mph. Retractable hardtop, carbon-fiber McLaren Carbon Lightweight Architecture (MCLA), dihedral doors, and ~21 miles of all-electric range.', 'Miami, FL', false, true),
  ('mercedes-amg-c63-white', 'Mercedes-AMG', 'C63', 2024, 'sedan', 325, 'A Polar White Mercedes-AMG C63 in a parking garage, AMG Panamericana grille front and center. The current generation C63 runs a hand-built 2.0L turbo four paired with a rear-axle electric motor — 671 hp combined, 0–60 in 3.3 seconds. AMG-specific 5-spoke wheels, quad exhaust tips, and the aggressive front lip. Interior shows the AMG Performance steering wheel with red aluminum dial controls, the MBUX infotainment screen tilted toward the driver, and saddle brown leather sport seats with red carpeting. The most powerful production C-Class ever.', 'Miami, FL', false, true),
  ('mercedes-amg-cla35-black', 'Mercedes-AMG', 'CLA 35', 2024, 'sedan', 250, 'An Obsidian Black Mercedes-AMG CLA 35 4-door coupe. Turbocharged 2.0L AMG-tuned four-cylinder making 302 hp, 4MATIC AWD, 0–60 in 4.8 seconds. CLA 35-badged decklid, multi-spoke AMG wheels, and the swooping CLS-inspired four-door silhouette. Murdered-out factory finish with subtle AMG body kit and a sport-tuned exhaust. The entry point to the AMG lineup — affordable to drive, fast enough to embarrass much more expensive cars off the line.', 'Miami, FL', false, true),
  ('mercedes-amg-gls63-white', 'Mercedes-AMG', 'GLS 63', 2024, 'suv', 425, 'A Polar White Mercedes-AMG GLS 63 — the full-size flagship AMG SUV. Hand-built 4.0L twin-turbo V8 producing 603 hp, 4MATIC+ all-wheel drive, 0–60 in 4.1 seconds despite weighing nearly 6,000 lbs. AMG Panamericana grille, 23-inch black AMG forged wheels, AMG sport exhaust, and full chrome side rails. Interior shows the dual-screen MBUX cockpit, AMG flat-bottom steering wheel, and three rows of black leather seating making it equally at home as a daily family hauler or executive shuttle.', 'Miami, FL', false, true),
  ('mercedes-amg-gt43-silver', 'Mercedes-AMG', 'GT 43 4-Door Coupe', 2024, 'supercar', 400, 'An Iridium Silver Mercedes-AMG GT 43 4-Door Coupe — the four-door grand tourer based on the AMG GT platform. Turbocharged 3.0L inline-six with EQ Boost making 362 hp, 4MATIC+ all-wheel drive, 0–60 in 4.8 seconds. AMG-specific Panamericana grille, frameless windows, sloping fastback roofline, and matte-black AMG wheels. Interior shows the dual-screen MBUX cockpit, AMG flat-bottom steering wheel with mode selectors, and the standout saddle-brown diamond-stitched Nappa leather seats — a four-door supercar that swallows luggage and four adults.', 'Miami, FL', false, true),
  ('mercedes-amg-sl55-white', 'Mercedes-AMG', 'SL 55 Roadster', 2024, 'convertible', 400, 'A Polar White Mercedes-AMG SL 55 roadster posed against the Miami skyline with the soft top retracted. The reborn SL — built entirely by AMG — runs a hand-built 4.0L twin-turbo V8 making 469 hp and 516 lb-ft of torque, 4MATIC+ all-wheel drive, 0–60 in 3.8 seconds. AMG Panamericana grille, yellow-painted AMG calipers behind black 5-spoke wheels, and the iconic three-pointed star hood ornament reborn as a body-color crest. Interior shows the AMG steering wheel, portrait-orientation MBUX touchscreen, and the AMG drive-mode selector dial. A modern grand-touring roadster with no compromises.', 'Miami, FL', false, true),
  ('mercedes-benz-c63s-amg-whiteblack', 'Mercedes-AMG', 'C 63 S (White/Black)', 2024, 'supercar', 525, 'A Mercedes-AMG C 63 S in Polar White over black interior. Hand-built 2.0L turbo four-cylinder paired with a rear-axle electric motor producing 671 hp combined — the most powerful production C-Class ever, 0–60 in 3.3 seconds. AMG Panamericana grille, AMG-specific aero, quad exhaust, and the AMG Performance steering wheel with red drive-mode dials. PHEV powertrain with ~8 miles of EV range.', 'Miami, FL', false, true),
  ('mercedes-benz-g63-amg-whitered', 'Mercedes-AMG', 'G 63 (White/Red)', 2024, 'suv', 1200, 'A Mercedes-AMG G 63 in Polar White over Bengal Red interior. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking differentials, 0–60 in 4.4 seconds. AMG Panamericana grille, AMG side-exit quad exhaust, and the unmistakable boxy G-Wagon silhouette. Diamond-stitched red Nappa interior. The benchmark luxury off-roader and ultimate Miami SUV.', 'Miami, FL', false, true),
  ('mercedes-benz-gle-63s', 'Mercedes-AMG', 'GLE 63 S', 2024, 'suv', 650, 'A Mercedes-AMG GLE 63 S 4MATIC+ — the V8 AMG mid-size SUV. Hand-built 4.0L twin-turbo V8 with EQ Boost producing 603 hp, 4MATIC+ AWD, 0–60 in 3.7 seconds, top speed 174 mph. AMG Panamericana grille, AMG sport exhaust, 22-inch AMG forged wheels, and the AMG performance steering wheel paired with diamond-stitched Nappa sport seats. The benchmark V8 AMG SUV.', 'Miami, FL', false, true),
  ('mercedes-benz-gle53-whiteblack', 'Mercedes-AMG', 'GLE 53 (White/Black)', 2024, 'suv', 500, 'A Mercedes-AMG GLE 53 4MATIC+ in Polar White over black interior. Turbocharged 3.0L inline-six with EQ Boost producing 429 hp, 4MATIC+ AWD, 0–60 in 4.9 seconds. AMG body kit, 22-inch AMG wheels, AMG-specific Panamericana grille, and the dual-screen MBUX cockpit. The mid-tier AMG SUV — bigger and more usable than a C-Class, sharper and faster than a stock GLE.', 'Miami, FL', false, true),
  ('mercedes-benz-gle63s-silverred', 'Mercedes-AMG', 'GLE 63 S (Silver/Red)', 2024, 'suv', 650, 'A Mercedes-AMG GLE 63 S 4MATIC+ in Iridium Silver over Bengal Red interior. Hand-built 4.0L twin-turbo V8 with EQ Boost producing 603 hp, 4MATIC+ AWD, 0–60 in 3.7 seconds, top speed 174 mph. AMG Panamericana grille, AMG sport exhaust, 22-inch AMG forged wheels, and the AMG performance steering wheel paired with diamond-stitched red Nappa sport seats. The benchmark mid-size AMG SUV.', 'Miami, FL', false, true),
  ('mercedes-maybach-gls600-obsidian-black-kalahari-gold-black', 'Mercedes-Maybach', 'GLS 600 (Obsidian Black / Kalahari Gold)', 2024, 'suv', 1800, 'A Mercedes-Maybach GLS 600 in two-tone Obsidian Black over Kalahari Gold paint with black interior — the flagship Maybach SUV. Twin-turbo 4.0L V8 with EQ Boost producing 550 hp, 4MATIC AWD, 0–60 in 4.8 seconds. Maybach-exclusive double-louvre grille, Executive Rear Seat Package with reclining captain chairs, refrigerator, champagne flutes, and rear entertainment. The ultimate chauffeured-or-driven experience.', 'Miami, FL', false, true),
  ('mercedes-s580-white', 'Mercedes-Benz', 'S 580', 2024, 'sedan', 400, 'A Diamond White Mercedes-Benz S 580 — the flagship S-Class luxury sedan. Twin-turbo 4.0L V8 with EQ Boost making 496 hp, 4MATIC AWD, 0–60 in 4.4 seconds. AMG-styling Line bodywork, multi-spoke 21-inch wheels, and the chrome-trimmed Mercedes grille with the iconic three-pointed star hood ornament. Interior is the showstopper — Bengal Red diamond-stitched Nappa leather front seats and rear executive seats, the massive portrait MBUX touchscreen with Hyperscreen-adjacent ambient lighting, and the new-generation steering wheel with capacitive controls. The car heads of state and Fortune 500 CEOs ride in.', 'Miami, FL', false, true),
  ('mercedes-g63', 'Mercedes-AMG', 'G 63', 2024, 'suv', 1200, 'A Mercedes-AMG G 63 — the iconic boxy SUV with AMG performance. Hand-built 4.0L twin-turbo V8 producing 577 hp, 4MATIC AWD with three locking differentials, 0–60 in 4.4 seconds. AMG Panamericana grille, AMG side-exit quad exhaust, and the unmistakable G-Wagon silhouette refined for the modern era.', 'Miami, FL', false, true),
  ('porsche-911-carrera-red', 'Porsche', '911 Carrera Cabriolet', 2024, 'convertible', 525, 'A Guards Red Porsche 911 Carrera Cabriolet with the top down, parked on a brick coastal driveway with the ocean behind it. Black 5-spoke alloys, body-color side mirrors, and the unmistakable 992-generation 911 silhouette. Twin-turbo flat-six rear-mid layout, sub-4-second 0–60, and a fully retractable soft top. Interior shot shows the iconic three-spoke steering wheel with the Porsche crest centered over a clean digital/analog instrument cluster. Top-down Miami cruiser, classic 911 lines with daily-driver comfort.', 'Miami, FL', false, true),
  ('rr-dawn-black-badge', 'Rolls-Royce', 'Dawn Black Badge', 2024, 'convertible', 2800, 'A Rolls-Royce Dawn Black Badge — the convertible Rolls-Royce in its sportier alter-ego trim. Twin-turbo 6.6L V12 producing 593 hp (Black Badge tune), RWD, 0–60 in 4.9 seconds, top speed 155 mph. Black Badge styling: blacked-out chrome, Spirit of Ecstasy in black, dark forged wheels, and a more aggressive throttle and transmission tune. Soft-top retracts in 22 seconds at speeds up to 31 mph. Rare in the wild.', 'Miami, FL', false, true),
  ('rolls-royce-cullinan-blackblack', 'Rolls-Royce', 'Cullinan (Black/Black)', 2024, 'suv', 2500, 'A Rolls-Royce Cullinan in Diamond Black over black interior — the only SUV from Rolls-Royce. Twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.8 seconds, top speed 155 mph. Air suspension, rear-wheel steering, magic carpet ride quality, and a stand-up tailgate "Recreation Module" with cocktail or viewing platform. The murdered-out Cullinan is the ultimate flex SUV — luxury, presence, and unmistakable Rolls-Royce gravitas.', 'Miami, FL', false, true),
  ('rolls-royce-cullinan', 'Rolls-Royce', 'Cullinan', 2024, 'suv', 2500, 'A Rolls-Royce Cullinan — the only SUV from Rolls-Royce. Twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.8 seconds, top speed 155 mph. Air suspension, rear-wheel steering, magic carpet ride quality, and a stand-up tailgate "Recreation Module" with cocktail or viewing platform. The Cullinan is the ultimate luxury SUV — Rolls-Royce gravitas in a daily-driver chassis.', 'Miami, FL', false, true),
  ('rolls-royce-ghost', 'Rolls-Royce', 'Ghost', 2024, 'sedan', 2200, 'A Rolls-Royce Ghost — the four-door entry into the Rolls family. Twin-turbo 6.75L V12 producing 563 hp, AWD, 0–60 in 4.6 seconds, top speed 155 mph. Planar Suspension System with predictive cameras for ride quality, full Starlight headliner option, suicide-hinged rear doors, and the iconic Spirit of Ecstasy hood ornament. The everyday Rolls-Royce.', 'Miami, FL', false, true),
  ('rolls-royce-spectre', 'Rolls-Royce', 'Spectre', 2024, 'grand-tourer', 3500, 'A Rolls-Royce Spectre — the brand''s first all-electric coupe. Dual electric motors producing 577 hp / 664 lb-ft, AWD, 0–60 in 4.4 seconds, range ~291 miles. Two-door fastback silhouette, suicide-hinged rear doors, full Starlight headliner with 4,796 fiber-optic stars, and the silent torque-rich electric powertrain that finally suits the Rolls-Royce ethos perfectly. The future of the brand.', 'Miami, FL', false, true),
  ('tailor-made-488-spider', 'Ferrari', '488 Spider (Tailor Made)', 2024, 'convertible', 2200, 'A Ferrari 488 Spider commissioned through Ferrari''s exclusive Tailor Made program — meaning bespoke paint, leather selection, exposed carbon fiber, and one-of-one specification details unavailable to standard ordering. Mid-mounted twin-turbo 3.9L V8 producing 661 hp, 7-speed dual-clutch, RWD, 0–60 in 3.0 seconds, top speed 203 mph. The 488 Spider was Ferrari''s last small-V8 convertible before the F8 replaced it.', 'Miami, FL', false, true),
  ('tesla-cybertruck', 'Tesla', 'Cybertruck', 2024, 'suv', 700, 'A Tesla Cybertruck — Tesla''s polarizing stainless steel pickup. Tri-motor "Cyberbeast" trim produces 845 hp, dual-motor AWD, 0–60 in 2.6 seconds, range up to 320 miles. Bulletproof-grade 30X stainless steel exoskeleton, 35-inch all-terrain tires, air suspension, and rear-wheel steering. The most-photographed truck in any city. Massive 6.5ft bed with built-in 110V/240V outlets and integrated tonneau.', 'Miami, FL', false, true),
  ('urus-performante', 'Lamborghini', 'Urus Performante', 2024, 'suv', 2000, 'A Lamborghini Urus Performante — the track-focused, lightened, more powerful Urus. Twin-turbo 4.0L V8 producing 657 hp, AWD with center diff biased rearward, 0–60 in 3.3 seconds, top speed 190 mph. 47mm wider track, 20mm lowered ride height, carbon-fiber hood with NACA ducts, fixed roof spoiler, and titanium Akrapovič exhaust. The fastest production SUV around the Nürburgring at its 2022 launch.', 'Miami, FL', false, true),
  ('widebody-g63-amg-custom', 'Mercedes-AMG', 'G 63 (Custom Widebody)', 2024, 'suv', 1500, 'A Mercedes-AMG G 63 with a custom widebody conversion — likely Brabus, Mansory, or Hofele bodywork adding 100+mm of width per side via forged carbon-fiber fenders, custom front bumper, side exit exhausts, and aftermarket forged wheels. Underneath, the 4.0L twin-turbo V8 producing 577 hp (or higher with tune). The wildest factory-plus-aftermarket spec for the world''s most aggressive luxury SUV.', 'Miami, FL', false, true);
