insert into public.yachts (slug, builder, model, year, category, length_ft, daily_rate, description, base_marina, featured, available) values
  ('103ft-luxury-azimut-w-toys-yach', 'Azimut', '103ft  with Toys', 2024, 'motor-yacht', 103, 18000, 'A 103ft Azimut tri-deck mega-yacht with full water-toys complement — jet skis, Seabobs, paddleboards, snorkeling gear, kayaks, and beach toys. Four to five cabins below including full-beam master, VIP, and twin cabins. Three living decks: main with formal dining and salon, upper sky lounge with bar and panoramic glass, and a sun deck with jacuzzi. Twin MTU diesels with stabilizers and full crew. Five-star Italian luxury. (Note: gallery images were not retrievable from the source listing.)', 'Miami, FL', false, true),
  ('110ft-maiora-yacht', 'Maiora', '110ft', 2024, 'motor-yacht', 110, 22000, 'A 110ft Maiora tri-deck Italian mega-yacht — built by the legendary Fipa Group in Viareggio, the same yard line that also produces AB Yachts and CRN. Five-cabin layout with full-beam master, VIP forward, twin and double guest cabins, full crew quarters with captain''s suite. Three living decks, formal dining, sky lounge, and sundeck with jacuzzi. Twin MTU diesels with full stabilization. Old-money Italian craftsmanship.', 'Miami, FL', false, true),
  ('118-azimut-grande-tycoon', 'Azimut', '118ft  Grande "Tycoon"', 2024, 'motor-yacht', 118, 28000, 'A 118ft Azimut Grande named "Tycoon" — flagship Italian mega-yacht from Azimut Grande series, the luxury-builder top tier. Five to six cabins for guests including a full-beam master suite with private balcony, VIP suites, twin and double guest cabins. Three living decks of formal dining, sky lounge, and sundeck with jacuzzi. Full crew quarters. Twin MTU diesels with active stabilizers. The Grande series is hand-built in the Avigliana yard with bespoke interior options.', 'Miami, FL', false, true),
  ('118-azimut', 'Azimut', '118ft', 2024, 'motor-yacht', 118, 25000, 'A 118ft Azimut tri-deck mega-yacht — flagship Italian motor yacht with full-beam master suite, VIP forward, twin and double guest cabins, plus full crew quarters. Three living decks of hosting space, formal dining, sky lounge, and sundeck with jacuzzi. Twin MTU diesels with active stabilization. The benchmark Italian flagship for Miami-based luxury charter.', 'Miami, FL', false, true),
  ('120-majesty', 'Majesty', '120ft', 2024, 'motor-yacht', 120, 26000, 'A 120ft Majesty mega-yacht — built by Gulf Craft in the UAE, Majesty Yachts is the brand favored by Middle Eastern and Mediterranean owners for its bold styling and generous interior volumes. Five to six cabins, full-beam master, VIP suites, twin guest cabins, full crew quarters. Three living decks, formal dining, sky lounge, sundeck with jacuzzi. Twin MTU diesels with active stabilizers.', 'Miami, FL', false, true),
  ('130ft-azimut-infinity-w-jacuzzi', 'Azimut', '130ft  "Infinity" with Jacuzzi', 2024, 'motor-yacht', 130, 30000, 'A 130ft Azimut named "Infinity" with sundeck jacuzzi — flagship Italian mega-yacht with five to six cabins, full-beam master with private balcony, multiple VIP suites, twin guest cabins, and full crew quarters. Three living decks: main with formal salon and dining, upper sky lounge with full bar, and the sundeck featuring the showpiece jacuzzi, sun loungers, and wet bar. Twin MTU diesels with active stabilizers. Charter-grade luxury.', 'Miami, FL', false, true),
  ('135ft-w-jacuzzi', 'Mega-Yacht', '135ft  with Jacuzzi', 2024, 'motor-yacht', 135, 35000, 'A 135ft tri-deck mega-yacht with sundeck jacuzzi — six cabins for guests including a full-beam master, VIP suites, twin and double guest cabins, plus full crew quarters. Three living decks of hosting space: main with formal salon and dining, upper sky lounge with full bar and panoramic glass, and the showpiece sundeck with jacuzzi, sun pad, and entertainment area. Twin diesel main propulsion with active stabilizers. The big-charter benchmark.', 'Miami, FL', false, true),
  ('206-rossinavi', 'Rossinavi', '206ft', 2024, 'motor-yacht', 206, 90000, 'A 206ft Rossinavi superyacht — Italian Viareggio-built ultra-luxury, the kind of vessel that anchors out as a destination. Six to eight cabins for guests with a full-beam owner suite, multiple VIP suites, plus complete crew quarters. Multiple decks of formal and casual hosting, beach-club tender garage, full water-toys complement, helipad-ready tonnage, and active stabilization. Twin large-bore diesels. Charter rates put this at the top of the market for Miami and Bahamas-based hosting.', 'Miami, FL', false, true),
  ('25ft-easy-yamaha-225xd', 'Yamaha', '25ft  225XD Center Console', 2024, 'sport-yacht', 25, 850, 'A 25ft Yamaha 225XD center console — a sporty day boat ideal for sandbar runs, snorkeling trips, or quick island hops. Twin Yamaha outboards push it through the bay quickly with great fuel economy. Open layout with bow and stern seating, T-top for shade, and a head compartment. Easy to handle, fits 8–10 guests comfortably for a Miami day on the water.', 'Miami, FL', false, true),
  ('40ft-vandutch-2017', 'VanDutch', '40ft  2017', 2017, 'sport-yacht', 40, 3200, 'A 40ft VanDutch 2017 — the iconic Dutch-built day cruiser that defined modern minimalist yacht design. Clean low-profile silhouette, twin diesel inboards delivering 35+ knots, and a full open cockpit with sun pad, dinette, and forward sun lounger. Below deck offers a private cabin for changing or overnighting. The yacht of choice for well-known clientele in Miami, St. Tropez, and Ibiza for a reason — it always turns heads.', 'Miami, FL', false, true),
  ('45ft-fjord-yacht', 'Fjord', '45ft  Open', 2024, 'sport-yacht', 45, 3800, 'A 45ft Fjord Open day cruiser — the Norwegian-designed, German-built sportboat known for its aggressive plumb bow and wide-open social cockpit. Twin Volvo Penta IPS pods, joystick docking, and a top speed in the high 30-knot range. Cockpit converts seamlessly between dining, sun-lounging, and entertaining modes; a private cabin and head are below.', 'Miami, FL', false, true),
  ('50ft-fountaine-pajot-2023-happy', 'Fountaine Pajot', '50ft  "Happy" (2023)', 2023, 'catamaran', 50, 4500, 'A 2023 Fountaine Pajot 50ft power catamaran named "Happy" — multihull stability, an enormous flybridge, and a wide-beam main deck that feels like a 70ft monohull. Two-engine catamaran efficiency, 4 cabins below, full galley, two heads, and the signature Fountaine Pajot wraparound salon glass. Massive aft deck with sun pads and dining. Perfect for groups who want comfort, low-roll cruising, and overnight capability.', 'Miami, FL', false, true),
  ('52ft-azimut-sport-luxury-yacht', 'Azimut', '52ft  Sport Luxury', 2024, 'sport-yacht', 52, 3800, 'A 52ft Azimut sport-luxury yacht — Italian designed and built, blending the sport-yacht aesthetic with full flybridge usability. Three cabins below (master, VIP, twin), two heads, and full galley. The main deck salon flows into a covered cockpit, and the flybridge delivers 360° views with a second helm, lounge, and bar. Twin diesels, hydraulic swim platform, and the unmistakable Azimut chrome-trimmed silhouette.', 'Miami, FL', false, true),
  ('52ft-the-ark-flybridge-yacht', 'The Ark', '52ft "" Flybridge', 2024, 'sport-yacht', 52, 3500, 'A 52ft flybridge motor yacht named "The Ark" — three levels of social space across a swim platform, main deck cockpit, and full upper flybridge with helm, wet bar, and sun pads. Below deck features a master suite, VIP cabin, twin bunks, and crew quarters. Twin diesel inboards. The classic Miami charter platform — versatile enough for sandbar lunches, sunset cruises, or overnight Bahamas runs.', 'Miami, FL', false, true),
  ('52ft-pershing-velocity', 'Pershing', '52ft  "Velocity"', 2024, 'sport-yacht', 52, 4200, 'A 52ft Pershing named "Velocity" — Italian Pershing is the brand for owners who want supercar speed at sea. Twin diesel inboards with surface drives push it well past 40 knots. Aggressive sport yacht profile with the iconic curved hardtop, retractable sunroof, full galley below, master and VIP cabins, and a sport-tuned exhaust note. The Lamborghini of yachts in this size class.', 'Miami, FL', false, true),
  ('53ft-2023-galeon-yacht', 'Galeon', '53ft  (2023)', 2023, 'sport-yacht', 53, 4000, 'A 2023 Galeon 53ft — the Polish-built yacht line known for its convertible "Beach Mode" cockpit where the side bulwarks fold down to extend the deck out over the water. Three cabin layout, two heads, full galley up, panoramic salon glass, and an enormous flybridge with sun lounger and helm. Modern hull, twin Volvo IPS pods for joystick docking.', 'Miami, FL', false, true),
  ('54ft-prestigie-500fly-yacht', 'Prestige', '54ft  500 Fly', 2024, 'sport-yacht', 54, 3800, 'A 54ft Prestige 500 Fly — French-built by Jeanneau Group and sister-brand to Beneteau. Three private cabins, the iconic Prestige private master with offset bed and walk-around space, two heads, full galley, and a generous covered flybridge with sun pad, dinette, and helm. Twin Volvo IPS pods make docking effortless. A favorite owner-operator yacht for South Florida and Bahamas cruising.', 'Miami, FL', false, true),
  ('55ft-galeon-yacht', 'Galeon', '55ft', 2024, 'sport-yacht', 55, 4100, 'A 55ft Galeon flybridge yacht — Polish craftsmanship paired with the brand''s signature transformable layouts including drop-down balconies and convertible Beach Mode platform. Three cabins, two-three heads, full galley, panoramic salon, and a sweeping flybridge with second helm and entertaining space. Twin diesel inboards. Big-boat presence at a mid-size price point.', 'Miami, FL', false, true),
  ('56ft-azimut-fly-dream-ii-ftll', 'Azimut', '56ft  Fly "Dream II" (Fort Lauderdale)', 2024, 'sport-yacht', 56, 4200, 'A 56ft Azimut Flybridge named "Dream II" based out of Fort Lauderdale — Italian Azimut design with three cabins, two-three heads, an extended flybridge with full helm, sun pads, and bar. Twin diesel inboards and bow thruster make for confident handling at any size. The Azimut chrome-detailed exterior and sleek raised pilothouse profile make this one of the most photographed boats in any marina it visits.', 'Miami, FL', false, true),
  ('57ft-azimut-yacht', 'Azimut', '57ft', 2024, 'motor-yacht', 57, 4300, 'A 57ft Azimut flybridge — Italian-built three-cabin layout, full galley up, convertible salon-to-dining great room, and a generous flybridge with second helm and entertaining lounge. Twin diesel inboards, bow and stern thrusters, hydraulic swim platform, and the unmistakable Azimut profile.', 'Miami, FL', false, true),
  ('59ft-princess-yacht', 'Princess', '59ft', 2024, 'sport-yacht', 59, 4500, 'A 59ft Princess flybridge — British craftsmanship, built in Plymouth UK with the heritage of one of the most respected yacht brands in the world. Three cabin layout (master, VIP, twin), two-three heads, full galley, and a flybridge with second helm, wet bar, and sun pads. Twin Volvo IPS pods or shaftdrives. Conservative classic styling that always looks right at any marina.', 'Miami, FL', false, true),
  ('60ft-azimut-flybridge-vdv', 'Azimut', '60ft  Flybridge "VDV"', 2024, 'sport-yacht', 60, 5000, 'A 60ft Azimut Flybridge named "VDV" — three-cabin Italian layout with the brand-signature chrome trim, raised pilothouse, and three-deck living. Master suite forward with private head, VIP amidships, twin cabin, and crew quarters. Full galley, salon dining, covered cockpit, and a flybridge with full helm, lounge, and dinette. A go-to South Florida charter platform.', 'Miami, FL', false, true),
  ('63ft-pershing-finstar-yacht', 'Pershing', '63ft  "Finstar"', 2024, 'sport-yacht', 63, 6500, 'A 63ft Pershing named "Finstar" — Italian Pershing performance pedigree at flagship size. Twin or triple diesel inboards with surface drives push 40+ knots, the signature curved hardtop with sliding sunroof, master and VIP cabins below, and a sport-yacht profile that turns heads at every dock.', 'Miami, FL', false, true),
  ('63ft-life-is-great-yacht', 'Is', '63ft "Life  Great"', 2024, 'motor-yacht', 63, 5500, 'A 63ft yacht aptly named "Life Is Great" — three cabin layout, full flybridge with second helm and entertaining space, twin diesel inboards, and a covered aft cockpit ready for dining or sun lounging. Master suite, VIP cabin, and twin bunks below. Full galley, multi-zone living, and the kind of presence that makes every Miami sandbar trip feel like a proper yacht charter.', 'Miami, FL', false, true),
  ('64ft-pershing-wind', 'Pershing', '64ft  "Wind"', 2024, 'sport-yacht', 64, 6800, 'A 64ft Pershing named "Wind" — flagship Italian sport-yacht performance with twin or triple diesels, surface drives, and 40+ knot top speed. Hardtop with sunroof, master and VIP suites below, full galley, and the iconic aggressive Pershing profile that defined the modern sport-yacht segment. (Note: gallery images were not retrievable from the source listing.)', 'Miami, FL', false, true),
  ('68ft-money-waves-yacht', 'Waves"', '68ft "Money', 2024, 'motor-yacht', 68, 6500, 'A 68ft flybridge yacht named "Money Waves" — three to four cabins below, twin diesel inboards, full flybridge with helm, sun pads, dinette, and bar. Spacious salon with panoramic glass, full galley, multiple heads, and an extended swim platform. The kind of boat that is built for the Miami sandbar lifestyle — big enough for groups, fast enough for Bahamas runs.', 'Miami, FL', false, true),
  ('70ft-galeon-yacht', 'Galeon', '70ft', 2024, 'sport-yacht', 70, 7800, 'A 70ft Galeon — Polish-built flagship featuring the brand-signature transformable Beach Mode cockpit, drop-down balconies, and panoramic salon. Four cabins below with crew quarters, full galley, formal dining, and a flybridge with second helm, sun pads, and dinette. Twin diesel inboards. The Galeon is the modern alternative to the legacy Italian flagships at this size.', 'Miami, FL', false, true),
  ('70ft-azimut-fly-le-grand-bleu-ya', 'Azimut', '70ft  Fly "Le Grand Bleu"', 2024, 'sport-yacht', 70, 7500, 'A 70ft Azimut Flybridge named "Le Grand Bleu" — flagship Italian three- to four-cabin layout, full beam master suite, full galley, covered cockpit, and a vast flybridge with second helm and full entertaining setup. Twin diesel inboards, bow/stern thrusters, hydraulic swim platform, and Azimut''s signature chrome-trimmed silhouette. Built for week-long luxury charter or all-day sandbar entertaining.', 'Miami, FL', false, true),
  ('70ft-azimut-flybridge-days-like', 'Azimut', '70ft  Flybridge "Days Like"', 2024, 'sport-yacht', 70, 7500, 'A 70ft Azimut Flybridge named "Days Like" — four-cabin Italian flagship-tier layout, master suite full beam, VIP forward, two twin cabins, plus crew quarters. Full galley up, formal dining salon, covered cockpit, and an enormous flybridge with second helm, sun loungers, dinette, and wet bar. Twin diesel inboards with stabilizers. Premium Miami-charter and Bahamas-cruising platform.', 'Miami, FL', false, true),
  ('72ft-azimut-flybridge-yacht', 'Azimut', '72ft  Flybridge', 2024, 'sport-yacht', 72, 8000, 'A 72ft Azimut Flybridge — flagship four-cabin Italian motor yacht with full-beam master, VIP forward, twin cabins, and crew quarters. Full galley up, formal salon dining, covered aft cockpit, and a vast flybridge with helm, sun loungers, and full bar. Twin diesel inboards with stabilizers, bow/stern thrusters. The Azimut benchmark in this size — luxurious, fast enough for Bahamas hops, and unmistakable in profile.', 'Miami, FL', false, true),
  ('75ft-sunseeker-yacht', 'Sunseeker', '75ft', 2024, 'sport-yacht', 75, 8500, 'A 75ft Sunseeker — British luxury motor yacht built in Poole, UK, the brand favored by James Bond films and global owners alike. Four cabins below with full-beam master, VIP, twin cabins and crew quarters. Twin MAN diesels. Full galley, dining salon, covered aft deck with bar, and a generous flybridge with second helm and entertaining space. The hallmark Sunseeker profile is unmistakable on any waterfront.', 'Miami, FL', false, true),
  ('78ft-sunseeker-do-it-anyways', 'Sunseeker', '78ft  "Do It Anyways"', 2024, 'sport-yacht', 78, 9500, 'A 78ft Sunseeker named "Do It Anyways" — British-built flagship-tier four-cabin Sunseeker with full-beam master amidships, VIP forward, twin cabins, and crew quarters. Twin MAN diesels, hydraulic swim platform, full galley, dining salon, multiple heads, and a vast flybridge with second helm, hot tub option, sun pads, and bar. The yacht-charter sweet spot for groups of 8–12 in luxury.', 'Miami, FL', false, true),
  ('92ft-hargave-mega-yacht', 'Hargrave', '92ft  Mega-Yacht', 2024, 'motor-yacht', 92, 14000, 'A 92ft Hargrave mega-yacht — Florida-built tri-deck motor yacht with five cabins (master, VIP, two twins, captain''s cabin), full crew quarters separately accessed, twin Caterpillar diesels, and full stabilizers. Three living decks: main with full galley and formal salon, upper sky lounge, and flybridge with helm and full bar. Hargrave is Fort Lauderdale''s premier custom builder — every yacht is one-of-one.', 'Miami, FL', false, true);
