insert into public.aircraft (slug, manufacturer, model, year, category, passengers, range_nm, cruise_speed_kts, ceiling_ft, cabin_height_ft, hourly_rate, description, base_airport, featured, available) values
  ('challenger-850', 'Bombardier', 'Challenger 850', 2024, 'heavy-jet', 14, 2250, 459, null, 6.08, 6500, 'The Bombardier Challenger 850 is a corporate-shuttle conversion of the CRJ-200 regional airliner, offering the largest stand-up cabin in its class at 48.4 ft long with a 6.08 ft ceiling. 14-passenger executive layout with a forward galley, full club seating, lounge area, divan, and a private aft lavatory. Twin GE CF34-3B1 engines, Rockwell Collins Pro Line 4 avionics. Range of 2,250 nm makes it ideal for sports teams, executive groups, and band tours where cabin volume matters more than ultimate range.', 'Opa-locka · KOPF', false, true),
  ('citation-cj1-plus', 'Cessna', 'Citation CJ1+', 2024, 'light-jet', 5, 1300, 389, null, 4.76, 2400, 'The Cessna Citation CJ1+ is a single-pilot certified light jet — the entry rung of the Citation Jet series. 5-passenger cabin, twin Williams FJ44-1AP turbofans, and Rockwell Collins Pro Line 21 avionics with FADEC engine management. Range of 1,300 nm and short-field performance make it ideal for hopping between regional airports the airlines don''t serve. The CJ1+ refresh adds redesigned engines, AutoThrottles availability, and a more efficient cabin layout. The ideal owner-pilot or charter step-up from turboprops.', 'Opa-locka · KOPF', false, true),
  ('citation-vi', 'Cessna', 'Citation VI', 2024, 'light-jet', 8, 2054, 468, null, 5.8, 3800, 'The Cessna Citation VI is a mid-size business jet seating up to 8 passengers in a stand-up cabin. With a transcontinental range of 2,054 nm and a cruise speed of 468 KTAS, it covers most US coast-to-city pairs nonstop. Twin Pratt & Whitney Canada JT15D-5 turbofans, two pilots, and a comfortable 5.8 ft cabin height make this a reliable workhorse for short- to medium-haul charter — Miami to New York, Vegas, or Caribbean runs without a fuel stop.', 'Opa-locka · KOPF', false, true),
  ('citation-xls-plus', 'Cessna', 'Citation XLS+', 2024, 'mid-jet', 9, 1858, 341, null, 5.7, 3500, 'The Citation XLS+ is one of the best-selling mid-size business jets in history. Up to 9 passengers in a 5.7 ft stand-up cabin with a flat floor, generous baggage capacity, and the ability to access shorter runways than larger jets. Twin Pratt & Whitney Canada PW545C turbofans, Rockwell Collins Pro Line 21 avionics, and FADEC-controlled engine management. Range of 1,858 nm covers most regional missions — Miami to Aspen, Cabo, or Boston nonstop. The XLS+ refresh adds redesigned engines, autothrottles, and an updated cockpit.', 'Opa-locka · KOPF', false, true),
  ('falcon-900dx', 'Dassault', 'Falcon 900DX', 2024, 'heavy-jet', 15, 4100, 481, null, 6.18, 7500, 'The Dassault Falcon 900DX is a large-cabin three-engine business jet seating up to 15 passengers in a 6.18 ft stand-up cabin. Three Honeywell TFE731-60 engines provide twin-engine performance with tri-jet redundancy — a Dassault hallmark for transoceanic operations. Range of 4,100 nm covers nonstop missions like NY-Geneva, Miami-São Paulo, or LA-Hawaii-and-back-with-payload. EASy II flight deck (Honeywell Primus Epic). Multi-zone cabin with a forward galley, full lavatory, and rear stateroom. The choice of operators who want intercontinental reach with the safety margin of three engines.', 'Opa-locka · KOPF', false, true),
  ('falcon-900lx', 'Dassault', 'Falcon 900LX', 2024, 'heavy-jet', 15, 4500, 481, null, 6.18, 7800, 'The Dassault Falcon 900LX is the long-range, high-Mach evolution of the 900 family with high-Mach blended winglets that extend range to 4,500 nm. 15-passenger large-cabin layout with three lounge zones, a galley, full lavatory, and an aft stateroom convertible to crew rest. Three Honeywell TFE731-60 engines provide twin-engine economics with tri-jet redundancy and short-runway capability. EASy II flight deck. Capable of NY-Tel Aviv direct, LA-Hawaii with payload, or Miami-Buenos Aires nonstop. The favored long-range tri-jet for owners flying into challenging airports.', 'Opa-locka · KOPF', false, true),
  ('gulfstream-g150', 'Gulfstream', 'G150', 2024, 'mid-jet', 8, 2294, 459, null, 5.75, 4200, 'The Gulfstream G150 is the entry into the Gulfstream family — built by IAI in Israel with Gulfstream''s design and certification. 8-passenger cabin with the widest cabin in its class at the time of release, twin Honeywell TFE731-40R engines, and a max cruise of 459 KTAS. Range of 2,294 nm covers transcontinental US missions and most Caribbean/Mexican destinations from East Coast departure points. Honeywell Primus Epic avionics. A solid Gulfstream-quality experience at mid-size operating costs.', 'Opa-locka · KOPF', false, true),
  ('gulfstream-g400', 'Gulfstream', 'G400', 2024, 'heavy-jet', 13, 4100, 505, null, 6.18, 7800, 'The Gulfstream G400 is the modern reimagining of the popular GIV/G400 lineage on Gulfstream''s all-new clean-sheet platform. 13-passenger large-cabin layout with three living zones, panoramic Gulfstream oval windows, and the lowest cabin altitude in class. Pratt & Whitney Canada PW812GA engines, Symmetry Flight Deck with active control sidesticks, and a 4,100 nm range that opens up transatlantic missions like NY-London or Miami-Buenos Aires. The do-it-all large-cabin jet for owners who want Gulfstream pedigree at a step below G500/G600 pricing.', 'Opa-locka · KOPF', false, true),
  ('gulfstream-g450', 'Gulfstream', 'G450', 2024, 'heavy-jet', 16, 4350, 500, null, 6.2, 8500, 'The Gulfstream G450 is the long-range evolution of the GIV-SP, with 4,350 nm capability and an enlarged forward fuselage adding crew rest and galley space. 16-passenger three-zone cabin with Gulfstream''s signature 14 panoramic windows, full berthing capability for up to 8 passengers, and a forward and aft lavatory. PlaneView flight deck with Honeywell Primus Epic avionics, Rolls-Royce Tay 611-8C engines. Capable of nonstop NY-London, LA-Hawaii, or Miami-Madrid. A core long-range business jet that''s defined the category for two decades.', 'Opa-locka · KOPF', false, true),
  ('gulfstream-giv-sp', 'Gulfstream', 'GIV-SP', 2024, 'heavy-jet', 16, 4109, 500, null, 6.2, 7500, 'The Gulfstream GIV-SP (Special Performance) is the upgraded variant of the legendary GIV — the jet that defined the large-cabin long-range business jet category. 16-passenger three-zone cabin, Rolls-Royce Tay 611-8 engines, and Gulfstream''s iconic 14 oval panoramic windows. Range of 4,109 nm covers most transatlantic missions plus Miami to São Paulo or LA to Honolulu nonstop. Honeywell SPZ-8400 avionics. Three lavatories on extended-range configurations, full galley, and complete cabin berthing for international red-eye flights.', 'Opa-locka · KOPF', false, true),
  ('hawker-400xp', 'Hawker', '400XP (Beechjet 400XP)', 2024, 'light-jet', 8, 1500, 450, null, 4.76, 2800, 'The Hawker 400XP is the modernized Beechjet 400 — a light jet with mid-size jet speed. Twin Pratt & Whitney Canada JT15D-5 turbofans, an 8-passenger double-club cabin, and Rockwell Collins Pro Line 21 avionics. Range of 1,500 nm covers most regional charter missions, and the high cruise of 450 KTAS keeps trip times competitive with much larger jets. A favorite of fractional operators for its efficient operating economics paired with strong climb and high-altitude performance.', 'Opa-locka · KOPF', false, true),
  ('hawker-850xp', 'Hawker', '850XP', 2024, 'mid-jet', 8, 2694, 426, null, 5.74, 4300, 'The Hawker 850XP is the winglet-upgraded version of the 800XP, adding Aviation Partners blended winglets that increase range to 2,694 nm and improve climb performance. 8-passenger double-club cabin, twin Honeywell TFE731-5BR engines, and the iconic wide oval Hawker fuselage that provides class-leading shoulder room. Rockwell Collins Pro Line 21 avionics with three large flat-panel LCDs. Capable of NY-LA, Miami-Caracas, or Aspen-Bahamas direct.', 'Opa-locka · KOPF', false, true),
  ('hawker-900xp', 'Hawker', '900XP', 2024, 'mid-jet', 9, 2818, 446, null, 5.74, 4500, 'The Hawker 900XP is Hawker Beechcraft''s modernized evolution of the 800XP — a true mid-size jet with intercontinental reach. 9-passenger double-club cabin, twin Honeywell TFE731-50R engines with winglets that extend range to 2,818 nm. Capable of New York to Los Angeles or Miami to most of South America nonstop. Rockwell Collins Pro Line 21 avionics, an oversized baggage compartment, and the wide oval Hawker fuselage that delivers more shoulder room than most jets in its class.', 'Opa-locka · KOPF', false, true),
  ('learjet-40xr', 'Bombardier', 'Learjet 40XR', 2024, 'light-jet', 6, 1617, 453, null, 4.9, 3200, 'The Learjet 40XR is the upgraded variant of the Learjet 40 — Bombardier''s light jet with the speed and ramp presence of a Learjet at light-jet operating costs. 6-passenger double-club cabin, twin Honeywell TFE731-20BR engines, and the XR refresh''s improved hot-and-high performance, faster climb, and increased takeoff weight. Range of 1,617 nm and Learjet''s signature 0.81 Mach high-speed cruise. Honeywell Primus 1000 avionics. The fast-charter-jet pick when a Citation just won''t do.', 'Opa-locka · KOPF', false, true),
  ('learjet-60', 'Bombardier', 'Learjet 60', 2024, 'mid-jet', 8, 2186, 465, null, 5.72, 3900, 'The Learjet 60 is the original best-selling mid-size from Bombardier''s Learjet division. Twin Pratt & Whitney Canada PW305A turbofans, an 8-passenger double-club cabin, and Learjet''s hallmark steep climb to FL410 in around 18 minutes. Range of 2,186 nm covers most US transcontinental city pairs. Honeywell Primus 1000 avionics. A workhorse jet known for ramp presence, brisk performance, and a punchy roll rate that pilots love.', 'Opa-locka · KOPF', false, true),
  ('learjet-60xr', 'Bombardier', 'Learjet 60XR', 2024, 'mid-jet', 8, 2365, 453, null, 5.72, 4200, 'The Learjet 60XR is the modernized variant of Bombardier''s mid-size 60-series. Twin Pratt & Whitney Canada PW305A turbofans push it to a cruise of 453 KTAS with a range of 2,365 nm — coast-to-coast US capable with appropriate winds. 8-passenger double-club cabin, Rockwell Collins Pro Line 21 avionics, and Learjet''s signature climb performance and ramp presence. The XR refresh adds a redesigned interior with larger windows and improved sound dampening over the original 60.', 'Opa-locka · KOPF', false, true);
